{"command": "cd /testbed && python3 -c "
from decimal import Decimal
# Check infinity and NaN
import math
for val in [float('inf'), float('-inf'), float('nan')]:
    print(f'repr: {repr(val)}')
    print(f'str: {str(val)}')
    try:
        d = Decimal(repr(val))
        print(f'Decimal(repr): {d}')
    except Exception as e:
        print(f'Decimal(repr) error: {e}')
    try:
        d = Decimal(str(val))
        print(f'Decimal(str): {d}')
    except Exception as e:
        print(f'Decimal(str) error: {e}')
    print()
""}

