{"command": "cd /testbed && python3 -c "
from decimal import Decimal
# Check if str and repr differ for any float
import random
for i in range(10000):
    f = random.random() * 1e10
    if Decimal(str(f)) != Decimal(repr(f)):
        print(f'Difference: {f}, str={str(f)}, repr={repr(f)}')
        break
else:
    print('No differences found in 10000 random floats')
""}

